import Vue from "vue";

const requireComponent = require.context(
  "./",
  true,
  /components\/[A-Z]\w+\.(vue)$/
);

requireComponent.keys().forEach((fileName) => {
  const name = fileName.replace(/^.*[\\/]/, "").replace(/\.[^.]+$/, "");
  console.log(name);
  Vue.component(name, () => import(`@/components/${name}`));
});
